CREATE OR REPLACE FUNCTION code()
RETURNS VARCHAR AS $$
DECLARE
chars TEXT[] := '{A,B,C,D,E,F,G,H}';
  result TEXT := '';
  i INTEGER;
BEGIN
FOR i IN 1..3 LOOP
    result := result || chars[1+i];
END LOOP;
RETURN result;
END;
$$ LANGUAGE plpgsql;

CREATE FUNCTION delete_deck_tree(p_id bigint) RETURNS void
            LANGUAGE plpgsql
            AS $$
        DECLARE
           r record;
        BEGIN
           DELETE FROM decks WHERE parent = p_id;

           FOR r IN SELECT id FROM decks WHERE parent = p_id LOOP
              PERFORM delete_deck_tree(r.id);
           END LOOP;

           DELETE FROM decks WHERE id = p_id;
        END;
        $$;

